import { describe, expect, it } from 'vitest';
import {
  addressToPrefixHash,
  isCanonicalDemoAddress,
  buildEnvelopeForAddress,
  teleportToken,
  resolveAddress,
  routeAddress,
  handleResolve,
  handleRoute,
  handleSeed,
  makeRegistry,
  CANONICAL_DEMO_PREFIX_HASH,
  CANONICAL_PREFIX_LEN,
  type SkymeshConfig,
  type AdmitResult,
} from './skymesh-route.mts';
import {
  PROTOCOL69_BROADCAST_SYMBOL,
  PROTOCOL69_EXPECTED_PROJECTION,
} from '../src/protocol69';

/** A config that never touches the network (no station, no peers, no live probe). */
function offlineConfig(overrides: Partial<SkymeshConfig> = {}): SkymeshConfig {
  return {
    foilUrl: 'http://127.0.0.1:8787/.aeon/protocol69',
    stationUrl: '',
    peers: [],
    // Default probe returns null so an unseeded address never resolves in tests.
    probeHolder: async () => null,
    ...overrides,
  };
}

describe('addressToPrefixHash', () => {
  it('is deterministic + stable for the same address', () => {
    const a = addressToPrefixHash('bafy-rhizome-content-address-xyz');
    const b = addressToPrefixHash('bafy-rhizome-content-address-xyz');
    expect(a).toEqual(b);
    expect(Number.isSafeInteger(a.prefixHash)).toBe(true);
    expect(a.prefixHash).toBeGreaterThanOrEqual(0);
    expect(a.prefixLen).toBe(CANONICAL_PREFIX_LEN);
  });

  it('differs for different addresses', () => {
    const a = addressToPrefixHash('address-one');
    const b = addressToPrefixHash('address-two');
    expect(a.prefixHash).not.toBe(b.prefixHash);
  });

  it('trims whitespace (same address with padding folds identically)', () => {
    expect(addressToPrefixHash('  addr-pad  ')).toEqual(addressToPrefixHash('addr-pad'));
  });

  it('maps the canonical demo address onto the live FOIL key 66/7', () => {
    for (const a of ['canonical', '66/7', 'aeon://rhizome/canonical']) {
      expect(isCanonicalDemoAddress(a)).toBe(true);
      const coords = addressToPrefixHash(a);
      expect(coords.prefixHash).toBe(CANONICAL_DEMO_PREFIX_HASH);
      expect(coords.prefixHash).toBe(PROTOCOL69_BROADCAST_SYMBOL);
      expect(coords.prefixLen).toBe(CANONICAL_PREFIX_LEN);
    }
  });

  it('a non-canonical address folds to a different prefixHash than the canonical key', () => {
    const other = addressToPrefixHash('some-other-rhizome-cid');
    expect(other.prefixHash).not.toBe(CANONICAL_DEMO_PREFIX_HASH);
  });
});

describe('buildEnvelopeForAddress', () => {
  it('projects to 69 for the canonical broadcast symbol (the sovereign gate)', () => {
    const env = buildEnvelopeForAddress('canonical');
    expect(env.broadcastSymbol).toBe(PROTOCOL69_BROADCAST_SYMBOL);
    expect(env.expectedProjection).toBe(PROTOCOL69_EXPECTED_PROJECTION);
  });

  it('a forged broadcast symbol does NOT project to 69', () => {
    const env = buildEnvelopeForAddress('canonical', 67); // 67 XOR 7 = 64
    expect(env.expectedProjection).not.toBe(PROTOCOL69_EXPECTED_PROJECTION);
  });
});

describe('resolveAddress / handleResolve', () => {
  it('a seeded address resolves to its holder', async () => {
    const registry = makeRegistry();
    handleSeed({ address: 'aeon://rhizome/abc', holder: 'http://peer-1:9000' }, registry);
    const result = await resolveAddress('aeon://rhizome/abc', registry, offlineConfig());
    expect(result.resolved).toBe(true);
    expect(result.holder).toBe('http://peer-1:9000');
    expect(result.addr).toBe('aeon://rhizome/abc');
    expect(typeof result.prefixHash).toBe('number');
  });

  it('an unseeded address resolves false when no holder is found', async () => {
    const registry = makeRegistry();
    const result = await resolveAddress('aeon://rhizome/never-seen', registry, offlineConfig());
    expect(result.resolved).toBe(false);
    expect(result.holder).toBeUndefined();
  });

  it('handleResolve returns 400 for an empty address', async () => {
    const registry = makeRegistry();
    const r = await handleResolve({ address: '' }, registry, offlineConfig());
    expect(r.status).toBe(400);
  });

  it('resolves the canonical key via a live probe (gossip resolver)', async () => {
    const registry = makeRegistry();
    const config = offlineConfig({
      stationUrl: 'http://station:8080',
      probeHolder: async (addr) =>
        isCanonicalDemoAddress(addr) ? 'http://station:8080' : null,
    });
    const result = await resolveAddress('canonical', registry, config);
    expect(result.resolved).toBe(true);
    expect(result.holder).toBe('http://station:8080');
  });
});

describe('routeAddress / handleRoute', () => {
  /** A station stub that admits the canonical key (HIT) and denies forged keys. */
  function stubAdmit(): SkymeshConfig['admit'] {
    return async (envelope): Promise<AdmitResult> => {
      if (envelope.expectedProjection !== PROTOCOL69_EXPECTED_PROJECTION) {
        return { outcome: 'denied', status: 403 };
      }
      return { outcome: 'hit', status: 200, geodesicLength: 0, replayMicros: 42 };
    };
  }

  it('a hit returns delivered:true, geodesicLength:0 + a token', async () => {
    const config = offlineConfig({ stationUrl: 'http://station:8080', admit: stubAdmit() });
    const result = await routeAddress('canonical', config);
    expect(result.delivered).toBe(true);
    expect(result.geodesicLength).toBe(0);
    expect(typeof result.token).toBe('string');
    expect(result.token).toContain('teleport:');
    expect(result.replayMicros).toBe(42);
  });

  it('the token is stable for the same address', async () => {
    const config = offlineConfig({ stationUrl: 'http://station:8080', admit: stubAdmit() });
    const a = await routeAddress('canonical', config);
    const b = await routeAddress('canonical', config);
    expect(a.token).toBe(b.token);
    expect(a.token).toBe(teleportToken('canonical', addressToPrefixHash('canonical')));
  });

  it('a forged/denied path returns delivered:false, reason:denied (fail-closed)', async () => {
    const config = offlineConfig({ stationUrl: 'http://station:8080', admit: stubAdmit() });
    const result = await routeAddress('canonical', config, { broadcastSymbolOverride: 67 });
    expect(result.delivered).toBe(false);
    expect(result.reason).toBe('denied');
    expect(result.token).toBeUndefined();
  });

  it('a station that denies (403) fails closed', async () => {
    const config = offlineConfig({
      stationUrl: 'http://station:8080',
      admit: async (): Promise<AdmitResult> => ({ outcome: 'denied', status: 403 }),
    });
    const result = await routeAddress('canonical', config);
    expect(result.delivered).toBe(false);
    expect(result.reason).toBe('denied');
  });

  it('a miss returns delivered:false, reason:miss with a chain hint', async () => {
    const config = offlineConfig({
      stationUrl: 'http://station:8080',
      admit: async (): Promise<AdmitResult> => ({ outcome: 'miss', status: 404 }),
    });
    const result = await routeAddress('some-uncaptured-address', config);
    expect(result.delivered).toBe(false);
    expect(result.reason).toBe('miss');
    expect(result.chainHint).toContain('/.aeon/chain');
  });

  it('no station configured -> honest miss (never a fake teleport)', async () => {
    // Use the real admit path (no injected stub) with an empty stationUrl.
    const config: SkymeshConfig = {
      foilUrl: 'http://127.0.0.1:8787/.aeon/protocol69',
      stationUrl: '',
      peers: [],
    };
    const result = await routeAddress('canonical', config);
    expect(result.delivered).toBe(false);
    expect(result.reason).toBe('miss');
  });

  it('handleRoute returns 400 for an empty address', async () => {
    const r = await handleRoute({ address: '' }, offlineConfig());
    expect(r.status).toBe(400);
  });

  it('handleRoute wraps a hit into a 200 envelope', async () => {
    const config = offlineConfig({ stationUrl: 'http://station:8080', admit: stubAdmit() });
    const r = await handleRoute({ address: 'canonical' }, config);
    expect(r.status).toBe(200);
    expect((r.body as { delivered: boolean }).delivered).toBe(true);
  });
});

describe('handleSeed', () => {
  it('seeds the registry and echoes the prefixHash', () => {
    const registry = makeRegistry();
    const r = handleSeed({ address: 'aeon://rhizome/seed-me' }, registry);
    expect(r.status).toBe(200);
    expect((r.body as { seeded: boolean }).seeded).toBe(true);
    expect(registry.has('aeon://rhizome/seed-me')).toBe(true);
  });

  it('returns 400 for an empty address', () => {
    const registry = makeRegistry();
    const r = handleSeed({ address: '' }, registry);
    expect(r.status).toBe(400);
  });
});
